DROP TABLE IF EXISTS `fatture`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fatture` (
  `id` int NOT NULL AUTO_INCREMENT,
  `id_cliente` int NOT NULL,
  `id_pagamenti` int NOT NULL,
  `link` longtext COLLATE utf8mb4_general_ci NOT NULL,
  `importo` double(10,2) NOT NULL,
  `bollo` double NOT NULL DEFAULT '0',
  `inps` double NOT NULL DEFAULT '0',
  `index` int NOT NULL,
  `data` date NOT NULL,
  `stato` enum('Pendente','Saldata') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Pendente',
  `metodo` enum('Pos','Contanti','Bonifico') COLLATE utf8mb4_general_ci NOT NULL,
  `request` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `fatturato_da` enum('Medplus','Isico') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Medplus',
  `confermato_dal_commercialista` tinyint(1) NOT NULL DEFAULT '0',
  `timestamp` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `id_cliente` (`id_cliente`),
  KEY `index` (`index`),
  KEY `id_pagamenti` (`id_pagamenti`),
  CONSTRAINT `fatture_cliente` FOREIGN KEY (`id_cliente`) REFERENCES `clienti` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `id_pagamenti` FOREIGN KEY (`id_pagamenti`) REFERENCES `pagamenti` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=1186 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
