DROP TABLE IF EXISTS `pagamenti_fatture`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pagamenti_fatture` (
  `id` int NOT NULL AUTO_INCREMENT,
  `id_origine` int NOT NULL,
  `id_origine_child` int DEFAULT NULL,
  `id_cliente` int NOT NULL,
  `id_fattura` int NOT NULL,
  `origine` enum('corsi','trattamenti') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `importo` double(10,2) NOT NULL,
  `timestamp` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `id_origine_child_origine` (`id_origine_child`,`origine`),
  KEY `pagamenti_fatture_cliente` (`id_cliente`),
  KEY `id_origine_child` (`id_origine_child`),
  KEY `pagamenti_fatture_fatture` (`id_fattura`),
  KEY `id_origine` (`id_origine`),
  CONSTRAINT `pagamenti_fatture_cliente` FOREIGN KEY (`id_cliente`) REFERENCES `clienti` (`id`) ON DELETE CASCADE,
  CONSTRAINT `pagamenti_fatture_fatture` FOREIGN KEY (`id_fattura`) REFERENCES `fatture` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=4878 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
