--
-- Table structure for table `pagamenti_senza_fattura`
--

DROP TABLE IF EXISTS `pagamenti_senza_fattura`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pagamenti_senza_fattura` (
  `id` int NOT NULL AUTO_INCREMENT,
  `id_cliente` int NOT NULL,
  `id_pagamenti` int NOT NULL,
  `id_origine` int NOT NULL,
  `id_origine_child` int DEFAULT NULL,
  `origine` enum('corsi','trattamenti') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `valore` double(10,2) NOT NULL,
  `data` date DEFAULT NULL,
  `metodo` enum('Pos','Contanti','Bonifico') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Contanti',
  `note` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `timestamp` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `id_origine_child_origine` (`id_origine_child`,`origine`),
  KEY `pagamenti_senza_fattura_cliente` (`id_cliente`),
  KEY `id_origine_child` (`id_origine_child`),
  KEY `id_origine` (`id_origine`),
  KEY `id_pagamenti` (`id_pagamenti`),
  CONSTRAINT `pagamenti_senza_fattura_cliente` FOREIGN KEY (`id_cliente`) REFERENCES `clienti` (`id`) ON DELETE CASCADE,
  CONSTRAINT `pagamenti_senza_fattura_id_pagamenti` FOREIGN KEY (`id_pagamenti`) REFERENCES `pagamenti` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=3931 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

