--
-- Table structure for table `percorsi_terapeutici_sedute`
--

DROP TABLE IF EXISTS `percorsi_terapeutici_sedute`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `percorsi_terapeutici_sedute` (
  `id` int NOT NULL AUTO_INCREMENT,
  `index` int DEFAULT NULL,
  `id_cliente` int DEFAULT NULL,
  `id_percorso` int DEFAULT NULL,
  `id_combo` int DEFAULT NULL,
  `id_terapista` int DEFAULT NULL,
  `id_pagamenti` int DEFAULT NULL,
  `percentuale_terapista` int DEFAULT NULL,
  `saldo_terapista` double(10,2) DEFAULT NULL,
  `stato_seduta` enum('Pendente','Assente','Conclusa','Prenotata') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Pendente',
  `stato_saldato_terapista` enum('Pendente','Saldato','Parziale','Esente') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Pendente',
  `data_seduta` date DEFAULT NULL,
  `data_pagamento` date DEFAULT NULL,
  `tipo_pagamento` enum('Senza Fattura','Aruba','Fattura','Isico','Esente') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `data_saldato_terapista` date DEFAULT NULL,
  `saldato_terapista` double(10,2) DEFAULT NULL,
  `prezzo` double(10,2) NOT NULL,
  `saldato` double(10,2) NOT NULL DEFAULT '0.00',
  `stato_pagamento` enum('Pendente','Saldato','Fatturato','Esente') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'Pendente',
  `timestamp` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `id_cliente` (`id_cliente`),
  KEY `id_ciclo` (`id_percorso`),
  KEY `id_trattamento` (`id_combo`),
  KEY `id_terapista` (`id_terapista`),
  KEY `id_pagamenti` (`id_pagamenti`),
  CONSTRAINT `cliente` FOREIGN KEY (`id_cliente`) REFERENCES `clienti` (`id`) ON DELETE CASCADE,
  CONSTRAINT `percorsi` FOREIGN KEY (`id_percorso`) REFERENCES `percorsi_terapeutici` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=12912 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

