CREATE DEFINER=`teo`@`localhost` PROCEDURE `debug_fatture`()
BEGIN
  DECLARE done INT DEFAULT 0;
  DECLARE fattura_id INT;
  DECLARE id_cliente INT;
  DECLARE metodo VARCHAR(50);
  DECLARE data_fattura DATE;
  DECLARE importo DECIMAL(10,2);
  DECLARE inps DECIMAL(10,2);
  DECLARE bollo DECIMAL(10,2);
  DECLARE stato VARCHAR(50);

  DECLARE cur CURSOR FOR 
    SELECT id, id_cliente, metodo, data, importo, inps, bollo, stato
    FROM fatture;

  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

  OPEN cur;
  read_loop: LOOP
    FETCH cur INTO fattura_id, id_cliente, metodo, data_fattura, importo, inps, bollo, stato;
    IF done THEN
      LEAVE read_loop;
    END IF;

    SELECT fattura_id, id_cliente, metodo, data_fattura, importo, inps, bollo, stato;
  END LOOP;
  CLOSE cur;
END ;;
