/*!50003 DROP PROCEDURE IF EXISTS `retro_update_pagamenti` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_unicode_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`teo`@`localhost` PROCEDURE `retro_update_pagamenti`()
BEGIN
  DECLARE done INT DEFAULT 0;
  DECLARE _id_cliente INT;
  DECLARE _metodo VARCHAR(50);
  DECLARE _data_fattura DATE;
  DECLARE _importo DECIMAL(10,2);
  DECLARE _inps DECIMAL(10,2);
  DECLARE _bollo DECIMAL(10,2);
  DECLARE _pag_id INT;
  DECLARE _stato VARCHAR(50);
  DECLARE _origine VARCHAR(50);

  DECLARE cur CURSOR FOR 
	SELECT f.id_cliente, f.metodo, f.data, f.valore, 0, 
           IF(f.valore > 77.47, 2.0, 0), 'Saldata', f.origine
	FROM medplus.pagamenti_senza_fattura f
	GROUP BY f.id_cliente, f.metodo, f.data, f.origine;

  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

  OPEN cur;
  read_loop: LOOP
    FETCH cur INTO _id_cliente, _metodo, _data_fattura, _importo, _inps, _bollo, _stato, _origine;
    IF done THEN
      LEAVE read_loop;
    END IF;

    INSERT INTO medplus.pagamenti (
      id_cliente, origine, metodo, data, imponibile, inps, bollo, totale, note, stato
    ) VALUES (
      _id_cliente, 'senza_fattura', _metodo, _data_fattura, _importo, _inps, _bollo,
      (_importo + _inps + _bollo), '', _stato
    );

    SET _pag_id = LAST_INSERT_ID();

    UPDATE medplus.pagamenti_senza_fattura f
    SET f.id_pagamenti = _pag_id
    WHERE f.id_cliente = _id_cliente
      AND f.metodo = _metodo
      AND f.data = _data_fattura
      AND f.origine = _origine;
  END LOOP;

  CLOSE cur;
END ;;
DELIMITER ;
