BEGIN
  DECLARE done INT DEFAULT 0;
  DECLARE fattura_id INT;
  DECLARE id_cliente INT;
  DECLARE metodo VARCHAR(50);
  DECLARE data_fattura DATE;
  DECLARE importo DECIMAL(10,2);
  DECLARE inps DECIMAL(10,2);
