 `pi`.`id_origine`) `pi` on((`pt`.`id` = `pi`.`id_origine`))) left join (select `pa`.`id_origine` AS `id_origine`,coalesce(sum(`pa`.`valore`),0) AS `totale_valore` from `pagamenti_aruba` `pa` where (`pa`.`origine` = 'trattamenti') group by `pa`.`id_origine`) `pa` on((`pt`.`id` = `pa`.`id_origine`))) left join (select `pf`.`id_origine` AS `id_origine`,`pf`.`origine` AS `origine`,sum((case when (`f`.`stato` = 'Saldata') then `pf`.`importo` else 0 end)) AS `saldato_fatture`,sum((case when (`f`.`stato` = 'Pendente') then `pf`.`importo` else 0 end)) AS `pendente_fatture` from (`pagamenti_fatture` `pf` left join `fatture` `f` on((`pf`.`id_fattura` = `f`.`id`))) where (`pf`.`origine` = 'trattamenti') group by `pf`.`id_origine`,`pf`.`origine`) `pf` on((`pt`.`id` = `pf`.`id_origine`))) union all select ('corsi' collate utf8mb4_general_ci) AS `origine`,`cc`.`realizzato_da` AS `realizzato_da`,`cp`.`id` AS `id`,`cp`.`id_cliente` AS `id_cliente`,`c`.`id` AS `id_origine`,`cc`.`bnw` AS `bnw`,`c`.`corso` AS `nome`,`c`.`corso` AS `acronimo`,(`cp`.`scadenza` collate utf8mb4_general_ci) AS `scadenza`,`cp`.`prezzo_tabellare` AS `prezzo_tabellare`,`cp`.`prezzo` AS `prezzo`,(((coalesce(`pf`.`saldato_fatture`,0) + coalesce(`psf`.`totale_valore`,0)) + coalesce(`pi`.`totale_valore`,0)) + coalesce(`pa`.`totale_valore`,0)) AS `saldato`,coalesce(`pf`.`pendente_fatture`,0) AS `fatturato`,(`cp`.`prezzo` - ((((coalesce(`pf`.`saldato_fatture`,0) + coalesce(`psf`.`totale_valore`,0)) + coalesce(`pi`.`totale_valore`,0)) + coalesce(`pa`.`totale_valore`,0)) + coalesce(`pf`.`pendente_fatture`,0))) AS `non_fatturato` from ((((((`corsi_pagamenti` `cp` left join `corsi_classi` `cc` on(((`cp`.`id_corso` = `cc`.`id_corso`) and (`cp`.`id_cliente` = `cc`.`id_cliente`) and (year(`cp`.`scadenza`) = year(`cc`.`data_inizio`))))) left join (select `psf`.`id_origine` AS `id_origine`,`psf`.`id_origine_child` AS `id_origine_child`,coalesce(sum(`psf`.`valore`),0) AS `totale_valore` from `pagamenti_senza_fattura` `psf` where (`psf`.`origine` = 'corsi') group by `psf`.`id_origine_child`) `psf` on((`cp`.`id` = `psf`.`id_origine_child`))) left join (select `pi`.`id_origine` AS `id_origine`,`pi`.`id_origine_child` AS `id_origine_child`,coalesce(sum(`pi`.`valore`),0) AS `totale_valore` from `pagamenti_isico` `pi` where (`pi`.`origine` = 'corsi') group by `pi`.`id_origine_child`) `pi` on((`cp`.`id` = `pi`.`id_origine_child`))) left join (select `pa`.`id_origine` AS `id_origine`,`pa`.`id_origine_child` AS `id_origine_child`,coalesce(sum(`pa`.`valore`),0) AS `totale_valore` from `pagamenti_aruba` `pa` where (`pa`.`origine` = 'corsi') group by `pa`.`id_origine_child`) `pa` on((`cp`.`id` = `pa`.`id_origine_child`))) left join (select `pf`.`id_origine` AS `id_origine`,`pf`.`id_origine_child` AS `id_origine_child`,`pf`.`origine` AS `origine`,sum((case when (`f`.`stato` = 'Saldata') then `pf`.`importo` else 0 end)) AS `saldato_fatture`,sum((case when (`f`.`stato` = 'Pendente') then `pf`.`importo` else 0 end)) AS `pendente_fatture` from (`pagamenti_fatture` `pf` left join `fatture` `f` on((`pf`.`id_fattura` = `f`.`id`))) where (`pf`.`origine` = 'corsi') group by `pf`.`id_origine_child`,`pf`.`origine`) `pf` on((`cp`.`id` = `pf`.`id_origine_child`))) left join `corsi` `c` on((`cp`.`id_corso` = `c`.`id`))) order by `id_cliente` desc */;
